$form = \App\Models\Form::where("slug", "pengajuan-isbn")->first(); $fields = $form->fields; $newFields = []; $changed = false; foreach($fields as $f) { if(str_contains($f["label"], "Unit Kerja") || str_contains($f["label"], "Satuan Kerja Pemohon")) { $f["type"] = "select_with_input"; $f["options"] = ["Kantor Wilayah (Kanwil)" => "Kantor Wilayah (Kanwil)", "Kemenag Kabupaten/Kota" => "Kemenag Kabupaten/Kota"]; $changed = true; } $newFields[] = $f; } if($changed) { $form->update(["fields" => $newFields]); echo "Updated successfully"; } else { echo "Not changed"; }
